// ═══════════════════════════════════════════════════════════
// BeeHarvest — product details page (details.js)
// ═══════════════════════════════════════════════════════════

const API_URL = "https://beeyond-harvest-admin.onrender.com/api";
let product = null;
let selectedQuantity = 1;
let cart = [];

// ═══════════════════════════════════════════════════════════
// UTILITIES
// ═══════════════════════════════════════════════════════════
function showToast(message, type = "info") {
  // Remove existing toasts of same type
  document.querySelectorAll(`.toast.${type}`).forEach((t) => t.remove());
  const t = document.createElement("div");
  t.className = `toast ${type}`;
  const icons = {
    success: "fa-check-circle",
    error: "fa-exclamation-circle",
    info: "fa-info-circle",
    warning: "fa-exclamation-triangle",
  };
  t.innerHTML = `<i class="fas ${icons[type]}"></i><span>${escapeHtml(message)}</span>`;
  document.body.appendChild(t);
  setTimeout(() => t.remove(), 3500);
}

function escapeHtml(str) {
  if (!str) return "";
  return String(str)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function formatCurrency(amount) {
  return `৳${(amount || 0).toLocaleString("bn-BD")}`;
}

function showLoadingOverlay() {
  document.getElementById("loadingOverlay")?.classList.add("active");
}

function hideLoadingOverlay() {
  document.getElementById("loadingOverlay")?.classList.remove("active");
}

function openModal(id) {
  const modal = document.getElementById(id);
  if (modal) {
    modal.classList.add("active");
    document.body.style.overflow = "hidden";
  }
}

function closeModal(id) {
  const modal = document.getElementById(id);
  if (modal) {
    modal.classList.remove("active");
    document.body.style.overflow = "";
  }
}

function goBack() {
  window.location.href = "index.html";
}

// ═══════════════════════════════════════════════════════════
// CART FUNCTIONS
// ═══════════════════════════════════════════════════════════
function loadCart() {
  try {
    const saved = localStorage.getItem("cart");
    if (saved) cart = JSON.parse(saved);
  } catch (e) {
    cart = [];
  }
}

function saveCart() {
  localStorage.setItem("cart", JSON.stringify(cart));
  updateCartBadge();
}

function updateCartBadge() {
  const count = cart.reduce((sum, item) => sum + item.quantity, 0);
  const badges = document.querySelectorAll("#cartCount");
  badges.forEach((badge) => {
    if (badge) badge.textContent = count;
  });
}

// ═══════════════════════════════════════════════════════════
// DELIVERY CHARGE FUNCTIONS (SAME AS MAIN PAGE)
// ═══════════════════════════════════════════════════════════
async function getDeliveryCharge(city, subtotal) {
  try {
    const params = new URLSearchParams();
    if (city) params.append("city", city);
    if (subtotal) params.append("subtotal", subtotal);

    const response = await fetch(`${API_URL}/delivery-charges/active?${params}`);
    const data = await response.json();

    if (data.success && data.data && data.data.amount !== undefined) {
      return data.data.amount;
    }
    return 60; // Default fallback
  } catch (error) {
    console.error("Failed to fetch delivery charge:", error);
    return 60;
  }
}

async function cartTotalsAsync(city = null, suppressToast = false) {
  const subtotal = cart.reduce((s, i) => s + i.price * i.quantity, 0);
  let shipping = 60;

  if (subtotal > 0) {
    try {
      const params = new URLSearchParams();
      if (city && city.trim()) {
        // Normalize city name (send as is - backend handles "dhaka" detection)
        params.append("city", city.trim());
      }
      params.append("subtotal", subtotal);

      const url = `${API_URL}/delivery-charges/active?${params}`;
      const response = await fetch(url);
      const data = await response.json();

      if (data.success && data.data && data.data.amount !== undefined) {
        shipping = data.data.amount;

        // Show toast only when not suppressed and city is provided
        if (!suppressToast && city) {
          if (city.toLowerCase() === "dhaka") {
            showToast(`ঢাকার জন্য ডেলিভারি চার্জ: ৳${shipping}`, "info");
          } else {
            showToast(`ঢাকার বাইরের জন্য ডেলিভারি চার্জ: ৳${shipping}`, "info");
          }
        }
        // Special offer notification for orders >= 999
        else if (!suppressToast && data.data.name === "default" && subtotal >= 999) {
          const regularCharge = city && city.toLowerCase() === "dhaka" ? 60 : 120;
          showToast(`🎉 স্পেশাল অফার! ${subtotal.toLocaleString()} টাকার অর্ডারে ডেলিভারি চার্জ মাত্র ৳${shipping} (নিয়মিত ৳${regularCharge})`, "success");
        }
      }
    } catch (error) {
      console.error("Failed to fetch delivery charge:", error);
      shipping = 60;
    }
  } else {
    shipping = 0;
  }

  return { subtotal, shipping, total: subtotal + shipping };
}

// ═══════════════════════════════════════════════════════════
// CHECKOUT FUNCTIONS
// ═══════════════════════════════════════════════════════════
async function openCheckout() {
  if (cart.length === 0) {
    showToast("কার্ট খালি! আগে পণ্য যোগ করুন", "error");
    return;
  }

  // Populate checkout items
  const itemsContainer = document.getElementById("coItemsList");
  if (itemsContainer) {
    itemsContainer.innerHTML = cart
      .map(
        (item) => `
        <div class="checkout-item">
          <img src="${escapeHtml(item.image || "https://via.placeholder.com/60")}" alt="${escapeHtml(item.name)}"
               onerror="this.src='https://via.placeholder.com/60'">
          <div class="checkout-item-details">
            <div class="checkout-item-name">${escapeHtml(item.name)}</div>
            <div class="checkout-item-meta">৳${item.price.toLocaleString()} × ${item.quantity}</div>
          </div>
          <div class="checkout-item-total">৳${(item.price * item.quantity).toLocaleString()}</div>
        </div>`
      )
      .join("");
  }

  // Get selected city and calculate totals
  const citySelect = document.getElementById("coCity");
  const selectedCity = citySelect ? citySelect.value : null;
  
  // Suppress toast when opening checkout
  const { subtotal, shipping, total } = await cartTotalsAsync(selectedCity, true);
  
  document.getElementById("coSubtotal").textContent = formatCurrency(subtotal);
  document.getElementById("coShipping").textContent = formatCurrency(shipping);
  document.getElementById("coTotal").textContent = formatCurrency(total);

  openModal("checkoutModal");
}

// Update checkout totals when city changes
async function updateCheckoutTotals() {
  const citySelect = document.getElementById("coCity");
  const city = citySelect ? citySelect.value : null;
  
  if (cart.length > 0) {
    // Show toast when user manually changes city
    const { subtotal, shipping, total } = await cartTotalsAsync(city, false);
    document.getElementById("coSubtotal").textContent = formatCurrency(subtotal);
    document.getElementById("coShipping").textContent = formatCurrency(shipping);
    document.getElementById("coTotal").textContent = formatCurrency(total);
  }
}

async function placeOrder() {
  if (cart.length === 0) {
    showToast("কার্ট খালি!", "error");
    return;
  }

  const name = document.getElementById("coName")?.value.trim();
  const email = document.getElementById("coEmail")?.value.trim();
  const phone = document.getElementById("coPhone")?.value.trim();
  const address = document.getElementById("coAddress")?.value.trim();
  const city = document.getElementById("coCity")?.value;
  const zip = document.getElementById("coZip")?.value.trim();
  const notes = document.getElementById("coNotes")?.value.trim();
  const payMethod = document.querySelector('input[name="payMethod"]:checked')?.value || "COD";
  const accepted = document.getElementById("coTerms")?.checked;

  if (!name || !email || !phone || !address || !city) {
    showToast("সব প্রয়োজনীয় তথ্য পূরণ করুন (*)", "error");
    return;
  }
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
    showToast("সঠিক ইমেইল ঠিকানা দিন", "error");
    return;
  }
  if (!/^01[3-9]\d{8}$/.test(phone)) {
    showToast("সঠিক মোবাইল নম্বর দিন (01XXXXXXXXX)", "error");
    return;
  }
  if (!accepted) {
    showToast("শর্তাবলী মেনে নিন", "error");
    return;
  }

  // Get dynamic shipping based on city (suppress toast during order placement)
  const { subtotal, shipping, total } = await cartTotalsAsync(city, true);

  const pmMap = {
    COD: "cash_on_delivery",
    bkash: "bkash",
    nagad: "nagad",
  };

  const orderData = {
    items: cart.map((i) => ({
      product: i.productId,
      name: i.name,
      price: i.price,
      quantity: i.quantity,
    })),
    customer: {
      name: name,
      email: email,
      phone: phone,
      address: {
        street: address,
        city: city,
        area: city,
        district: city,
        division: city,
        postalCode: zip || "",
      },
    },
    paymentMethod: pmMap[payMethod] || "cash_on_delivery",
    deliveryCharge: shipping,
    notes: notes || "",
  };

  showLoadingOverlay();
  const btn = document.getElementById("confirmBtn");
  if (btn) {
    btn.disabled = true;
    btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> প্রক্রিয়াকরণ...';
  }

  try {
    const res = await fetch(`${API_URL}/orders`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(orderData),
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.message || "অর্ডার দেওয়া যায়নি");
    if (!data.success) throw new Error(data.message || "অর্ডার ব্যর্থ");

    const orderNum = data.data?.orderNumber || data.data?._id?.slice(-8) || "SUCCESS";

    // Clear cart
    cart = [];
    saveCart();
    updateCartBadge();
    closeModal("checkoutModal");
    hideLoadingOverlay();

    document.getElementById("successOrderNum").textContent = `#${orderNum}`;

    setTimeout(() => {
      openModal("successModal");
      startConfetti();
      setTimeout(stopConfetti, 4000);
    }, 400);

    showToast("অর্ডার সফল হয়েছে! 🎉", "success");
    // Reset form
    document.getElementById("checkoutForm")?.reset();
  } catch (err) {
    hideLoadingOverlay();
    showToast(err.message || "অর্ডার দেওয়া যায়নি। আবার চেষ্টা করুন।", "error");
    console.error("Order error:", err);
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = '<i class="fas fa-check-circle"></i> অর্ডার কনফার্ম করুন';
    }
  }
}

// ═══════════════════════════════════════════════════════════
// PRODUCT FUNCTIONS
// ═══════════════════════════════════════════════════════════
function changeQty(delta) {
  const input = document.getElementById("qtyInput");
  let newVal = selectedQuantity + delta;
  if (product && product.stock !== undefined) {
    newVal = Math.min(Math.max(1, newVal), product.stock);
  } else {
    newVal = Math.max(1, newVal);
  }
  selectedQuantity = newVal;
  input.value = selectedQuantity;

  // Update note if stock is low
  const note = document.getElementById("qtyNote");
  if (product && product.stock <= 10 && product.stock > 0) {
    note.textContent = `মাত্র ${product.stock} টি স্টকে আছে`;
    note.style.color = "#f5a623";
  } else {
    note.textContent = "";
  }
}

function addToCart() {
  if (!product) return;
  if (product.stock <= 0) {
    showToast("এই পণ্যটি স্টকে নেই", "error");
    return;
  }
  if (selectedQuantity > product.stock) {
    showToast(`শুধুমাত্র ${product.stock} টি স্টকে আছে`, "error");
    return;
  }

  const existing = cart.find((item) => item.productId === product._id);
  if (existing) {
    existing.quantity += selectedQuantity;
    if (existing.quantity > product.stock) {
      existing.quantity = product.stock;
      showToast(`সর্বোচ্চ ${product.stock} টি পর্যন্ত অর্ডার করতে পারেন`, "warning");
    }
  } else {
    cart.push({
      productId: product._id,
      name: product.name,
      price: product.discountPrice || product.price,
      image: product.images?.[0]?.url || "https://via.placeholder.com/80",
      quantity: selectedQuantity,
    });
  }
  saveCart();
  updateCartBadge();
  showToast(`"${product.name}" কার্টে যোগ হয়েছে`, "success");
}

function buyNow() {
  if (!product) return;
  if (product.stock <= 0) {
    showToast("এই পণ্যটি স্টকে নেই", "error");
    return;
  }
  if (selectedQuantity > product.stock) {
    showToast(`শুধুমাত্র ${product.stock} টি স্টকে আছে`, "error");
    return;
  }

  // Clear cart and add this product
  cart = [];
  cart.push({
    productId: product._id,
    name: product.name,
    price: product.discountPrice || product.price,
    image: product.images?.[0]?.url || "https://via.placeholder.com/80",
    quantity: selectedQuantity,
  });
  saveCart();
  updateCartBadge();
  openCheckout();
}

function openCheckoutDirect() {
  openCheckout();
}

// ═══════════════════════════════════════════════════════════
// CONFETTI
// ═══════════════════════════════════════════════════════════
let confettiRaf = null;

function startConfetti() {
  const canvas = document.getElementById("confettiCanvas");
  if (!canvas) return;
  canvas.classList.add("active");
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
  const ctx = canvas.getContext("2d");
  const colors = ["#F5A623", "#FDD882", "#C47F11", "#0D1B3E", "#1A2E5A", "#28a745", "#ff6b6b"];
  const particles = Array.from({ length: 150 }, () => ({
    x: Math.random() * canvas.width,
    y: -20 - Math.random() * canvas.height,
    size: Math.random() * 8 + 3,
    color: colors[Math.floor(Math.random() * colors.length)],
    vy: Math.random() * 4 + 2,
    vx: (Math.random() - 0.5) * 2,
    rot: Math.random() * 360,
    rotV: (Math.random() - 0.5) * 6,
  }));
  function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    let alive = 0;
    for (const p of particles) {
      p.y += p.vy;
      p.x += p.vx;
      p.rot += p.rotV;
      if (p.y < canvas.height) alive++;
      ctx.save();
      ctx.translate(p.x, p.y);
      ctx.rotate((p.rot * Math.PI) / 180);
      ctx.fillStyle = p.color;
      ctx.fillRect(-p.size / 2, -p.size / 2, p.size, p.size * 0.6);
      ctx.restore();
    }
    if (alive > 0) confettiRaf = requestAnimationFrame(draw);
    else stopConfetti();
  }
  draw();
}

function stopConfetti() {
  const canvas = document.getElementById("confettiCanvas");
  if (canvas) {
    canvas.classList.remove("active");
    canvas.getContext("2d").clearRect(0, 0, canvas.width, canvas.height);
  }
  if (confettiRaf) {
    cancelAnimationFrame(confettiRaf);
    confettiRaf = null;
  }
}

// ═══════════════════════════════════════════════════════════
// LOAD PRODUCT
// ═══════════════════════════════════════════════════════════
async function loadProduct() {
  const urlParams = new URLSearchParams(window.location.search);
  // Try both 'id' and 'productId' parameters
  let productId = urlParams.get("id") || urlParams.get("productId");
  
  console.log("Looking for product with ID:", productId); // Debug log

  if (!productId) {
    console.error("No product ID found in URL. URL:", window.location.href);
    document.getElementById("loadingState").style.display = "none";
    document.getElementById("errorState").style.display = "flex";
    document.getElementById("errorMsg").innerHTML = `
      পণ্যের আইডি পাওয়া যায়নি।<br>
      <small style="font-size: 12px; margin-top: 8px; display: block;">URL: ${window.location.href}</small>
      <button class="btn-primary" style="margin-top: 16px;" onclick="goBack()">পণ্যের তালিকায় ফিরুন</button>
    `;
    return;
  }

  try {
    const response = await fetch(`${API_URL}/products/${productId}`);
    const data = await response.json();

    if (!response.ok || !data.success) {
      throw new Error(data.message || "পণ্য পাওয়া যায়নি");
    }

    product = data.data;
    renderProduct();
  } catch (err) {
    console.error("Error loading product:", err);
    document.getElementById("loadingState").style.display = "none";
    document.getElementById("errorState").style.display = "flex";
    document.getElementById("errorMsg").innerHTML = `
      ${err.message}<br>
      <small style="font-size: 12px; margin-top: 8px; display: block;">পণ্যটি খুঁজে পাওয়া যায়নি বা সরানো হয়েছে।</small>
      <button class="btn-primary" style="margin-top: 16px;" onclick="goBack()">পণ্যের তালিকায় ফিরুন</button>
    `;
  }
}

function renderProduct() {
  if (!product) return;

  document.getElementById("loadingState").style.display = "none";
  document.getElementById("productDetail").style.display = "block";
  document.title = `${product.name} — BeeHarvest`;

  // Breadcrumb
  document.getElementById("breadcrumbName").textContent = product.name;

  // Images
  const images = product.images || [];
  const mainImage = images[0]?.url || "https://via.placeholder.com/600x400?text=No+Image";
  document.getElementById("mainImage").src = mainImage;
  document.getElementById("mainImage").alt = product.name;

  // Thumbnails
  const thumbStrip = document.getElementById("thumbnailStrip");
  if (images.length > 1) {
    thumbStrip.innerHTML = images
      .map(
        (img, idx) => `
        <img class="thumb-img ${idx === 0 ? "active" : ""}" 
             src="${img.url}" 
             alt="${product.name} ${idx + 1}"
             onclick="changeImage('${img.url}', this)">
      `
      )
      .join("");
  } else {
    thumbStrip.innerHTML = "";
  }

  // Badges
  const badges = [];
  if (product.discountPrice) {
    const discount = Math.round(((product.price - product.discountPrice) / product.price) * 100);
    badges.push(`<span class="badge-off">-${discount}%</span>`);
  }
  if (product.isFeatured) badges.push(`<span class="badge-featured"><i class="fas fa-star"></i> ফিচার্ড</span>`);
  document.getElementById("imgBadges").innerHTML = badges.join("");

  // Category
  const categoryName = product.category?.name || "পণ্য";
  document.getElementById("categoryTag").innerHTML = `<span class="category-badge"><i class="fas fa-tag"></i> ${categoryName}</span>`;

  // Name
  document.getElementById("productName").textContent = product.name;

  // Meta tags
  const tags = product.tags || [];
  document.getElementById("metaTags").innerHTML = tags
    .map((tag) => `<span class="meta-tag">#${tag}</span>`)
    .join("");

  // Price
  const finalPrice = product.discountPrice || product.price;
  document.getElementById("priceMain").textContent = formatCurrency(finalPrice);
  if (product.discountPrice) {
    document.getElementById("priceOrig").style.display = "inline";
    document.getElementById("priceOrig").textContent = formatCurrency(product.price);
    const discount = Math.round(((product.price - product.discountPrice) / product.price) * 100);
    document.getElementById("priceOff").style.display = "inline";
    document.getElementById("priceOff").textContent = `${discount}% ছাড়`;
  }

  // Stock status
  const stockDiv = document.getElementById("stockStatus");
  if (product.stock <= 0) {
    stockDiv.innerHTML = `<div class="stock-badge out"><i class="fas fa-times-circle"></i> স্টকে নেই</div>`;
    document.getElementById("btnAddCart").disabled = true;
    document.getElementById("btnBuyNow").disabled = true;
  } else if (product.stock <= 10) {
    stockDiv.innerHTML = `<div class="stock-badge low"><i class="fas fa-exclamation-circle"></i> শেষ ${product.stock} টি</div>`;
  } else {
    stockDiv.innerHTML = `<div class="stock-badge in"><i class="fas fa-check-circle"></i> স্টকে আছে</div>`;
  }

  // Quantity max
  const qtyInput = document.getElementById("qtyInput");
  qtyInput.max = product.stock > 0 ? product.stock : 99;

  // Extras (SKU, weight, etc.)
  const extrasDiv = document.getElementById("productExtras");
  extrasDiv.innerHTML = `
    <div class="extra-card">
      <div class="extra-item"><i class="fas fa-barcode"></i> SKU: ${product.sku || "—"}</div>
      <div class="extra-item"><i class="fas fa-weight-hanging"></i> ওজন: ${product.weight || "—"}</div>
      <div class="extra-item"><i class="fas fa-tag"></i> ক্যাটাগরি: ${categoryName}</div>
    </div>
  `;

  // Load related products
  loadRelatedProducts();
}

function changeImage(url, thumbElement) {
  document.getElementById("mainImage").src = url;
  document.querySelectorAll(".thumb-img").forEach((img) => img.classList.remove("active"));
  thumbElement.classList.add("active");
}

async function loadRelatedProducts() {
  if (!product?.category?._id) return;

  try {
    const response = await fetch(`${API_URL}/products?category=${product.category._id}&limit=4`);
    const data = await response.json();
    const products = (data.data || []).filter((p) => p._id !== product._id).slice(0, 4);

    const relatedSection = document.getElementById("relatedSection");
    const relatedGrid = document.getElementById("relatedGrid");

    if (products.length === 0) {
      relatedSection.style.display = "none";
      return;
    }

    relatedGrid.innerHTML = products
      .map(
        (p) => `
        <div class="related-card" onclick="window.location.href='product-detail.html?id=${p._id}'">
          <img src="${p.images?.[0]?.url || "https://via.placeholder.com/150"}" alt="${escapeHtml(p.name)}" loading="lazy">
          <div class="related-info">
            <div class="related-name">${escapeHtml(p.name)}</div>
            <div class="related-price">${formatCurrency(p.discountPrice || p.price)}</div>
          </div>
        </div>
      `
      )
      .join("");

    relatedSection.style.display = "block";
  } catch (err) {
    console.error("Failed to load related products:", err);
  }
}

// ═══════════════════════════════════════════════════════════
// EVENT LISTENERS
// ═══════════════════════════════════════════════════════════
document.addEventListener("DOMContentLoaded", () => {
  loadCart();
  updateCartBadge();
  loadProduct();

  // Add city change listener for checkout modal
  const citySelect = document.getElementById("coCity");
  if (citySelect) {
    citySelect.addEventListener("change", updateCheckoutTotals);
  }

  // Close modals on backdrop click
  document.querySelectorAll(".modal").forEach((modal) => {
    modal.addEventListener("click", (e) => {
      if (e.target === modal) closeModal(modal.id);
    });
  });

  // Escape key
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") {
      document.querySelectorAll(".modal.active").forEach((modal) => closeModal(modal.id));
    }
  });

  // Resize confetti canvas
  window.addEventListener("resize", () => {
    const canvas = document.getElementById("confettiCanvas");
    if (canvas?.classList.contains("active")) {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    }
  });
});

// Global exports
window.changeQty = changeQty;
window.addToCart = addToCart;
window.buyNow = buyNow;
window.openCheckout = openCheckout;
window.placeOrder = placeOrder;
window.goBack = goBack;
window.changeImage = changeImage;
window.openCheckoutDirect = openCheckoutDirect;
window.closeModal = closeModal;
